using sv_f5cf05084c0a4f3ca7f37c5739813f27.Models;

namespace sv_f5cf05084c0a4f3ca7f37c5739813f27.Services;

public interface IRecipeService
{
    Task<List<Recipe>> GetByCuisineAsync(int cuisineId, CancellationToken cancellationToken);
}

public sealed class RecipeService : IRecipeService
{
    private static readonly Dictionary<int, List<Recipe>> SeedData = new()
    {
        [1] = new List<Recipe>
        {
            new(1, "Margherita Pizza", "Classic Neapolitan pizza with fresh mozzarella, basil, and San Marzano tomatoes.", 30),
            new(2, "Spaghetti Carbonara", "Creamy Roman pasta with guanciale, egg yolk, and Pecorino Romano.", 25),
            new(3, "Tiramisu", "Layered coffee-soaked ladyfingers with mascarpone cream.", 45),
            new(4, "Risotto alla Milanese", "Saffron-infused Arborio rice cooked slowly in broth.", 40),
        },
        [2] = new List<Recipe>
        {
            new(5, "Kung Pao Chicken", "Spicy stir-fried chicken with peanuts, chili peppers, and Sichuan peppercorns.", 35),
            new(6, "Mapo Tofu", "Silken tofu in a fiery sauce of doubanjiang, ground pork, and Sichuan pepper.", 20),
            new(7, "Xiaolongbao", "Delicate steamed soup dumplings filled with pork and rich broth.", 90),
            new(8, "Char Siu", "Cantonese barbecued pork glazed with honey and five-spice.", 60),
        },
        [3] = new List<Recipe>
        {
            new(9, "Chicken Tikka Masala", "Tandoori chicken pieces in a creamy, spiced tomato sauce.", 50),
            new(10, "Palak Paneer", "Fresh spinach purée with cubes of paneer cheese and aromatic spices.", 35),
            new(11, "Biryani", "Fragrant basmati rice layered with marinated meat and saffron.", 75),
            new(12, "Samosas", "Crispy pastry pockets filled with spiced potatoes and peas.", 55),
        },
    };

    public async Task<List<Recipe>> GetByCuisineAsync(int cuisineId, CancellationToken cancellationToken)
    {
        // Simulate a slow API call
        await Task.Delay(2000, cancellationToken);

        if (SeedData.TryGetValue(cuisineId, out var recipes))
        {
            return recipes;
        }

        return new List<Recipe>();
    }
}

@page "/recipes/{CuisineId:int}"
@rendermode InteractiveServer
@using sv_f5cf05084c0a4f3ca7f37c5739813f27.Models
@using sv_f5cf05084c0a4f3ca7f37c5739813f27.Services
@inject IRecipeService RecipeService
@inject ILogger<Recipes> Logger
@inject NavigationManager Navigation
@implements IDisposable

<PageTitle>Recipes</PageTitle>

<h1>Recipes</h1>

@if (_error is not null)
{
    <div class="alert alert-danger" role="alert">
        <p>@_error</p>
        <button class="btn btn-outline-danger" @onclick="RetryAsync">Retry</button>
    </div>
}
else if (_recipes is null)
{
    <p><em>Loading recipes…</em></p>
}
else
{
    @if (_isRefreshing)
    {
        <p><em>Refreshing…</em></p>
    }

    <table class="table">
        <thead>
            <tr>
                <th>Title</th>
                <th>Description</th>
                <th>Prep Time (min)</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var recipe in DisplayedRecipes)
            {
                <tr>
                    <td>@recipe.Title</td>
                    <td>@recipe.Description</td>
                    <td>@recipe.PrepTimeMinutes</td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    [Parameter]
    public int CuisineId { get; set; }

    [SupplyParameterFromQuery(Name = "sort")]
    public string? Sort { get; set; }

    private List<Recipe>? _recipes;
    private string? _error;
    private bool _isRefreshing;
    private int _loadedCuisineId;

    private CancellationTokenSource? _cts;

    private IEnumerable<Recipe> DisplayedRecipes => Sort?.ToLowerInvariant() switch
    {
        "newest" => _recipes!.OrderByDescending(r => r.Id),
        "popular" => _recipes!.OrderBy(r => r.PrepTimeMinutes),
        _ => _recipes!,
    };

    protected override Task OnParametersSetAsync()
    {
        // Only reload when cuisine changes, not when sort changes
        if (CuisineId != _loadedCuisineId)
        {
            return LoadRecipesAsync();
        }

        return Task.CompletedTask;
    }

    private async Task LoadRecipesAsync()
    {
        // Cancel any in-flight request
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = new CancellationTokenSource();
        var token = _cts.Token;

        _error = null;

        if (_recipes is not null)
        {
            _isRefreshing = true;
        }

        try
        {
            var results = await RecipeService.GetByCuisineAsync(CuisineId, token);
            token.ThrowIfCancellationRequested();

            _recipes = results;
            _loadedCuisineId = CuisineId;
            _isRefreshing = false;
        }
        catch (OperationCanceledException) when (token.IsCancellationRequested)
        {
            // Request was superseded or component disposed; do nothing
        }
        catch (TimeoutException ex)
        {
            Logger.LogError(ex, "Timeout loading recipes for cuisine {CuisineId}", CuisineId);
            _isRefreshing = false;
            _error = "The request timed out. Please try again.";
        }
        catch (Exception ex)
        {
            Logger.LogError(ex, "Error loading recipes for cuisine {CuisineId}", CuisineId);
            _isRefreshing = false;
            _error = "Something went wrong while loading recipes. Please try again.";
        }
    }

    private Task RetryAsync() => LoadRecipesAsync();

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

